 1→import { registerToDefault } from '../registry';
 2→import type { SDUIComponentRenderer } from '../models';
 3→
 4→import HeadingAdapter from './HeadingAdapter';
 5→import TextAdapter from './TextAdapter';
 6→import BalanceDisplayAdapter from './BalanceDisplayAdapter';
 7→import PointsInputAdapter from './PointsInputAdapter';
 8→import ButtonAdapter from './ButtonAdapter';
 9→import LinkAdapter from './LinkAdapter';
10→import AlertAdapter from './AlertAdapter';
11→import ListTextIconAdapter from './ListTextIconAdapter';
12→import SeparatorAdapter from './SeparatorAdapter';
13→import IconTextRowAdapter from './IconTextRowAdapter';
14→import SectionHeadingAdapter from './SectionHeadingAdapter';
15→
16→// FIXME: use something like "props: DUIProps<Foo, Bar>" during component
17→//  creation in order to avoid eliminate the use of "as SDUIComponentRenderer"
18→const adapters: Record<string, SDUIComponentRenderer> = {
19→  heading: HeadingAdapter as SDUIComponentRenderer,
20→  text: TextAdapter as SDUIComponentRenderer,
21→  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
22→  points_input: PointsInputAdapter as SDUIComponentRenderer,
23→  button: ButtonAdapter as SDUIComponentRenderer,
24→  link: LinkAdapter as SDUIComponentRenderer,
