 1→import React from 'react';
 2→import { View } from 'react-native';
 3→import type {
 4→  SDUIScreen,
 5→  SDUIComponent,
 6→  SDUIComponentRegistry,
 7→  SDUIContext,
 8→} from '../models';
 9→import { interpolateDeep } from '../utils/interpolation';
10→import { getDefaultRegistry, getRenderer } from '../registry';
11→import FallbackComponent from './FallbackComponent';
12→
13→interface ScreenRendererProps {
14→  screen: SDUIScreen;
15→  registry?: SDUIComponentRegistry;
16→}
17→
18→function renderComponent(
19→  component: SDUIComponent,
20→  context: SDUIContext,
21→  registry: SDUIComponentRegistry,
22→  key: string,
23→) {
24→  const interpolatedProps = interpolateDeep(component.props, context);
25→
26→  const Renderer = getRenderer(registry, component.type);
27→
28→  if (!Renderer) {
29→    return (
30→      <FallbackComponent
31→        key={key}
32→        type={component.type}
33→        props={interpolatedProps}
34→      />
35→    );
36→  }
37→
38→  return <Renderer key={key} props={interpolatedProps} context={context} />;
39→}
40→
41→export default function ScreenRenderer({
42→  screen,
43→  registry,
44→}: ScreenRendererProps) {
45→  const activeRegistry = registry ?? getDefaultRegistry();
46→  const { context, header, body, footer } = screen;
47→
48→  return (
49→    <View style={{ flex: 1 }}>
50→      {header && renderComponent(header, context, activeRegistry, 'header')}
51→
52→      <View style={{ flex: 1 }}>
53→        {(body ?? []).map((component, index) =>
54→          renderComponent(
55→            component,
56→            context,
57→            activeRegistry,
58→            `${component.type}-${index}`,
59→          ),
60→        )}
61→      </View>
62→
63→      {footer && renderComponent(footer, context, activeRegistry, 'footer')}
64→    </View>
65→  );
66→}
