  8→const HeadingAdapter = ({
  9→  props,
 10→}: {
 11→  props: SDUIComponentProps;
 12→  context: SDUIContext;
 13→}) => <Text testID="heading">{String(props.text)}</Text>;
 14→
 15→const ButtonAdapter = ({
 16→  props,
 17→}: {
 18→  props: SDUIComponentProps;
 19→  context: SDUIContext;
 20→}) => <Text testID="button">{String(props.label)}</Text>;
 21→
 22→function buildRegistry() {
 23→  let registry = createRegistry();
 24→  registry = registerComponent(registry, 'heading', HeadingAdapter);
 25→  registry = registerComponent(registry, 'button', ButtonAdapter);
 26→  return registry;
 27→}
